//! Profile Viewer - Utility to read and display ZiskEmu profiler JSON output
//!
//! This tool reads the Firefox Profiler format JSON files generated by the ZiskEmu
//! profiler and displays the samples with their associated function names, weights,
//! and time deltas.

use clap::Parser;
use flate2::read::GzDecoder;
use serde::Deserialize;
use std::fs::File;
use std::io::{BufReader, Read};
use std::path::Path;

/// Command line arguments
#[derive(Parser, Debug)]
#[command(author, version, about = "ZiskEmu Profile Viewer", long_about = None)]
struct Args {
    /// Path to the profile JSON file (.json or .json.gz)
    #[arg(value_name = "FILE")]
    file: String,

    /// Show only the first N samples (0 = show all)
    #[arg(short = 'n', long, default_value = "0")]
    limit: usize,

    /// Show full call stack for each sample
    #[arg(short = 's', long)]
    show_stack: bool,

    /// Output format (text, csv)
    #[arg(short = 'f', long, default_value = "text")]
    format: String,
}

/// Simplified structure for deserializing the profiler JSON
#[derive(Debug, Deserialize)]
struct ProfileData {
    shared: SharedData,
    threads: Vec<ThreadData>,
}

#[derive(Debug, Deserialize)]
struct SharedData {
    #[serde(rename = "stringArray")]
    string_array: Vec<String>,
    #[serde(rename = "stackTable")]
    stack_table: StackTable,
    #[serde(rename = "frameTable")]
    frame_table: FrameTable,
    #[serde(rename = "funcTable")]
    func_table: FuncTable,
}

#[derive(Debug, Deserialize)]
struct StackTable {
    frame: Vec<usize>,
    prefix: Vec<Option<usize>>,
}

#[derive(Debug, Deserialize)]
struct FrameTable {
    func: Vec<usize>,
}

#[derive(Debug, Deserialize)]
struct FuncTable {
    name: Vec<usize>,
}

#[derive(Debug, Deserialize)]
struct ThreadData {
    #[allow(dead_code)]
    name: String,
    samples: SamplesData,
}

#[derive(Debug, Deserialize)]
struct SamplesData {
    weight: Vec<f64>,
    stack: Vec<usize>,
    #[serde(rename = "timeDeltas")]
    time_deltas: Vec<f64>,
}

/// Sample information for display
#[derive(Debug)]
struct SampleInfo {
    index: usize,
    function_name: String,
    #[allow(dead_code)]
    function_string_idx: usize,
    call_stack: Vec<String>,
    #[allow(dead_code)]
    call_stack_indices: Vec<usize>,
    weight: f64,
    time_delta: f64,
    cumulative_time: f64,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args = Args::parse();

    // Read and parse the JSON file
    let profile_data = read_profile_file(&args.file)?;

    // Extract samples information
    let samples = extract_samples(&profile_data)?;

    // Display samples
    display_samples(&samples, &args)?;

    // Print summary statistics
    print_summary(&samples);

    Ok(())
}

/// Read and parse the profile JSON file (supports .json and .json.gz)
fn read_profile_file(filename: &str) -> Result<ProfileData, Box<dyn std::error::Error>> {
    let path = Path::new(filename);
    let file = File::open(path)?;
    let reader = BufReader::new(file);

    let json_string = if path.extension().and_then(|s| s.to_str()) == Some("gz") {
        // Decompress gzipped file
        let mut decoder = GzDecoder::new(reader);
        let mut json_string = String::new();
        decoder.read_to_string(&mut json_string)?;
        json_string
    } else {
        // Read regular JSON file
        let mut json_string = String::new();
        BufReader::new(File::open(path)?).read_to_string(&mut json_string)?;
        json_string
    };

    let profile_data: ProfileData = serde_json::from_str(&json_string)?;
    Ok(profile_data)
}

/// Extract sample information from the profile data
fn extract_samples(
    profile_data: &ProfileData,
) -> Result<Vec<SampleInfo>, Box<dyn std::error::Error>> {
    let shared = &profile_data.shared;

    // Get the first thread (main thread)
    let thread = profile_data.threads.get(0).ok_or("No threads found in profile data")?;

    let samples = &thread.samples;
    let mut sample_infos = Vec::new();
    let mut cumulative_time = 0.0;

    for (i, (&stack_idx, (&weight, &time_delta))) in
        samples.stack.iter().zip(samples.weight.iter().zip(samples.time_deltas.iter())).enumerate()
    {
        cumulative_time += time_delta;

        // Get the call stack for this sample
        let (function_name, function_string_idx, call_stack, call_stack_indices) =
            get_call_stack(stack_idx, shared);

        sample_infos.push(SampleInfo {
            index: i,
            function_name,
            function_string_idx,
            call_stack,
            call_stack_indices,
            weight,
            time_delta,
            cumulative_time,
        });
    }

    Ok(sample_infos)
}

/// Get the function name and full call stack for a given stack index
fn get_call_stack(
    stack_idx: usize,
    shared: &SharedData,
) -> (String, usize, Vec<String>, Vec<usize>) {
    let mut call_stack = Vec::new();
    let mut call_stack_indices = Vec::new();
    let mut current_idx = Some(stack_idx);

    // Walk up the stack chain
    while let Some(idx) = current_idx {
        if idx >= shared.stack_table.frame.len() {
            break;
        }

        let frame_idx = shared.stack_table.frame[idx];
        if frame_idx >= shared.frame_table.func.len() {
            break;
        }

        let func_idx = shared.frame_table.func[frame_idx];
        if func_idx >= shared.func_table.name.len() {
            break;
        }

        let name_idx = shared.func_table.name[func_idx];
        if name_idx >= shared.string_array.len() {
            break;
        }

        let function_name = shared.string_array[name_idx].clone();
        call_stack.push(format!("{} #{}", function_name, name_idx));
        call_stack_indices.push(name_idx);

        // Move to parent stack frame
        current_idx = shared.stack_table.prefix[idx];
    }

    // Reverse to get root -> leaf order
    call_stack.reverse();
    call_stack_indices.reverse();

    let function_name = call_stack.last().cloned().unwrap_or_else(|| "unknown #0".to_string());
    let function_string_idx = call_stack_indices.last().copied().unwrap_or(0);

    (function_name, function_string_idx, call_stack, call_stack_indices)
}

/// Display samples according to the specified format
fn display_samples(samples: &[SampleInfo], args: &Args) -> Result<(), Box<dyn std::error::Error>> {
    let limit = if args.limit == 0 { samples.len() } else { args.limit.min(samples.len()) };

    match args.format.as_str() {
        "csv" => display_csv(samples, limit, args.show_stack),
        "text" | _ => display_text(samples, limit, args.show_stack),
    }

    Ok(())
}

/// Display samples in text format
fn display_text(samples: &[SampleInfo], limit: usize, show_stack: bool) {
    println!("\n{:=<100}", "");
    println!("ZiskEmu Profile Samples");
    println!("{:=<100}\n", "");

    println!(
        "{:>6} {:>12} {:>12} {:>12}  {}",
        "Sample", "Weight", "TimeDelta", "CumTime", "Function"
    );
    println!("{:-<100}", "");

    for sample in samples.iter().take(limit) {
        println!(
            "{:>6} {:>12.3} {:>12.6} {:>12.6}  {}",
            sample.index,
            sample.weight,
            sample.time_delta,
            sample.cumulative_time,
            sample.function_name
        );

        if show_stack && sample.call_stack.len() > 1 {
            println!("       Call stack:");
            for (depth, func) in sample.call_stack.iter().enumerate() {
                println!("       {:>2}: {}", depth, func);
            }
            println!();
        }
    }

    if limit < samples.len() {
        println!("\n... ({} more samples not shown)", samples.len() - limit);
    }
}

/// Display samples in CSV format
fn display_csv(samples: &[SampleInfo], limit: usize, show_stack: bool) {
    if show_stack {
        println!("Sample,Weight,TimeDelta,CumulativeTime,Function,CallStack");
        for sample in samples.iter().take(limit) {
            let call_stack = sample.call_stack.join(" > ");
            println!(
                "{},{},{},{},\"{}\",\"{}\"",
                sample.index,
                sample.weight,
                sample.time_delta,
                sample.cumulative_time,
                sample.function_name,
                call_stack
            );
        }
    } else {
        println!("Sample,Weight,TimeDelta,CumulativeTime,Function");
        for sample in samples.iter().take(limit) {
            println!(
                "{},{},{},{},\"{}\"",
                sample.index,
                sample.weight,
                sample.time_delta,
                sample.cumulative_time,
                sample.function_name
            );
        }
    }
}

/// Print summary statistics
fn print_summary(samples: &[SampleInfo]) {
    if samples.is_empty() {
        println!("\nNo samples found.");
        return;
    }

    println!("\n{:=<100}", "");
    println!("Summary Statistics");
    println!("{:=<100}", "");

    let total_samples = samples.len();
    let total_weight: f64 = samples.iter().map(|s| s.weight).sum();
    let total_time = samples.last().map(|s| s.cumulative_time).unwrap_or(0.0);
    let avg_weight = total_weight / total_samples as f64;

    // Calculate weight statistics
    let mut weights: Vec<f64> = samples.iter().map(|s| s.weight).collect();
    weights.sort_by(|a, b| a.partial_cmp(b).unwrap());
    let min_weight = weights.first().copied().unwrap_or(0.0);
    let max_weight = weights.last().copied().unwrap_or(0.0);
    let median_weight = if weights.is_empty() {
        0.0
    } else if weights.len() % 2 == 0 {
        (weights[weights.len() / 2 - 1] + weights[weights.len() / 2]) / 2.0
    } else {
        weights[weights.len() / 2]
    };

    println!("Total samples:       {}", total_samples);
    println!("Total weight:        {:.3}", total_weight);
    println!("Total time:          {:.6} ms", total_time);
    println!("Average weight:      {:.3}", avg_weight);
    println!("Min weight:          {:.3}", min_weight);
    println!("Max weight:          {:.3}", max_weight);
    println!("Median weight:       {:.3}", median_weight);

    // Top 5 functions by cumulative weight
    let mut func_weights: std::collections::HashMap<String, f64> = std::collections::HashMap::new();
    for sample in samples {
        *func_weights.entry(sample.function_name.clone()).or_insert(0.0) += sample.weight;
    }

    let mut func_vec: Vec<_> = func_weights.iter().collect();
    func_vec.sort_by(|a, b| b.1.partial_cmp(a.1).unwrap());

    println!("\nTop 5 functions by cumulative weight:");
    for (i, (func, weight)) in func_vec.iter().take(5).enumerate() {
        println!(
            "  {}. {:<50} {:>12.3} ({:>6.2}%)",
            i + 1,
            func,
            weight,
            (*weight / total_weight) * 100.0
        );
    }

    println!("{:=<100}\n", "");
}
